useEffect(() => {
  if (!isTauri) return;

  let unsubscribe: (() => void) | undefined;
  let cancelled = false;

  getPlatform()
    .clipboard.onClipboardChange((event: ClipboardChangeEvent) => {
      if (cancelled) return;

      const isDuplicate = entriesRef.current.some(
        e => e.content === event.content && !e.pinned,
      );

      setEntries(prev => {
        let next: ClipboardEntry[];
        if (isDuplicate) {
          const existing = prev.find(e => e.content === event.content);
          if (existing) {
            next = [
              { ...existing, copiedAt: new Date(event.timestamp) },
              ...prev.filter(e => e.id !== existing.id),
            ];
          } else {
            next = [createEntryFromEvent(event), ...prev];
          }
        } else {
          next = [createEntryFromEvent(event), ...prev];
        }

        if (next.length > MAX_ENTRIES) {
          const pinned = next.filter(e => e.pinned);
          const unpinned = next.filter(e => !e.pinned);
          next = [...pinned, ...unpinned.slice(0, MAX_ENTRIES - pinned.length)];
        }

        persistEntries(next);
        return next;
      });
    })
    .then(unsub => {
      if (cancelled) {
        unsub();
      } else {
        unsubscribe = unsub;
      }
    });

  return () => {
    cancelled = true;
    unsubscribe?.();
  };
}, []);

