 20→function isStoredEntryArray(value: unknown): value is StoredEntry[] {
 21→  if (!Array.isArray(value)) return false;
 22→  return value.every(
 23→    v =>
 24→      typeof v === 'object' &&
 25→      v !== null &&
 26→      typeof (v as StoredEntry).id === 'string' &&
 27→      typeof (v as StoredEntry).content === 'string' &&
 28→      typeof (v as StoredEntry).contentType === 'string' &&
 29→      typeof (v as StoredEntry).copiedAt === 'string' &&
 30→      typeof (v as StoredEntry).pinned === 'boolean',
 31→  );
 32→}
 33→
 34→function serializeEntries(entries: ClipboardEntry[]): StoredEntry[] {
 35→  return entries.map(e => ({
