    });
  }, []);

  const deleteEntry = useCallback((entryId: string) => {
    setEntries(prev => {
      const next = prev.filter(e => e.id !== entryId);
      persistEntries(next);
      return next;
    });
  }, []);

  const clearAll = useCallback(() => {
    setEntries([]);
    persistEntries([]);
  }, []);

  return {
    entries,
    togglePin,
    deleteEntry,
    clearAll,
  };
}

